    Course(
      id: 'rage',
      name: 'Rage',
      cards: [
        Flashcard(id: 'rage_1', question: 'Qu\'est-ce que la rage ?', answer: 'Zoonose à transmission accidentelle à l\'homme. Encéphalomyélite constamment fatale une fois déclarée. Priorité de santé publique. MDO'),
        Flashcard(id: 'rage_2', question: 'Quel est l\'agent causal de la rage ?', answer: 'Lyssavirus de la famille des Rhabdoviridae. Virus à ARN monocaténaire enveloppé, fragile (détruit par savon, antiseptiques, chaleur, lumière)'),
        Flashcard(id: 'rage_3', question: 'Quels sont les 3 cycles épidémiologiques de la rage ?', answer: '1) Rage canine (pays d\'Afrique, Asie, Amérique latine) 2) Rage selvatique (renards, loups, ratons laveurs) 3) Rage des chiroptères (chauves-souris)'),
        Flashcard(id: 'rage_4', question: 'Quel animal est responsable de 99% des cas de rage humaine ?', answer: 'Le chien errant'),
        Flashcard(id: 'rage_5', question: 'Comment évolue la rage dans le système nerveux ?', answer: 'Point d\'inoculation → multiplication dans muscle strié → fixation aux terminaisons nerveuses → transport rétrograde axonal (8-22 mm/j) → SNC → diffusion centrifuge vers SN périphérique et glandes salivaires'),
        Flashcard(id: 'rage_6', question: 'Pourquoi la durée d\'incubation varie-t-elle ?', answer: 'D\'autant plus courte que la morsure est : proche du SNC (visage), dans une zone richement innervée (doigts, organes génitaux), ou que l\'inoculum est massif'),
        Flashcard(id: 'rage_7', question: 'Quelles sont les caractéristiques de la phase prodromique de la rage ?', answer: '2 à 10 jours : douleurs/paresthésies au niveau de la région mordue + troubles du comportement (anxiété, insomnie) + fièvre 38-39°C'),
        Flashcard(id: 'rage_8', question: 'Qu\'est-ce que l\'hydrophobie et l\'aérophobie dans la rage ?', answer: 'Spasmes pharyngo-laryngés violents et douloureux déclenchés par la vue de l\'eau (hydrophobie) ou par un courant d\'air (aérophobie)'),
        Flashcard(id: 'rage_9', question: 'Quelle est l\'évolution de la rage déclarée ?', answer: 'Constamment fatale : coma → paralysie cardiorespiratoire en 3-4 jours (rage furieuse) ou 5-6 jours (rage paralytique)'),
        Flashcard(id: 'rage_10', question: 'Quel est le traitement local immédiat d\'une morsure animale ?', answer: 'Lavage au savon de Marseille + rinçage jet d\'eau 15 min + eau javellisée + alcool 70° ou povidone iodée. Éviter la suture si possible'),
        Flashcard(id: 'rage_11', question: 'Quels sont les 2 schémas vaccinaux antirabiques reconnus par l\'OMS (verorab) ?', answer: 'Essen : J0-J3-J7-J14-J28 (IM). Zagreb : 2 injections J0 + J7 + J21 (IM)'),
        Flashcard(id: 'rage_12', question: 'Quelle est la durée d\'observation vétérinaire de l\'animal mordeur ?', answer: '14 jours (animaux contaminants 5-7 jours avant les 1ers symptômes)'),
        Flashcard(id: 'rage_13', question: 'Qu\'est-ce que l\'immunodéprimé doit obligatoirement recevoir en post-exposition ?', answer: 'Immunoglobulines antirabiques + vaccin selon protocole Essen obligatoirement'),
      ],
